// Script Continued Below
(function executeRule(current, previous /*null when async*/) {

	// RAJ for now, don't set members
	var alist = ' ';
	var officeMembersQuery = new GlideRecordSecure('x_153465_discovert_discover_office_members');
	if (!current.original_tasker_inst.nil() ) {
		var grTaskInst = new GlideRecord('x_153465_discovert_route_task_instance');
		if(grTaskInst.get(current.getValue("original_tasker_inst"))){
			// if the task was assigned to a user we may want to come back here and set it to a user.
			// RJ - STRY0065465 there is no longer an 'Assigne_to_type, just assign user, if assigned, it will just assign null if it wasn't selected in template
			current.assigned_to_individual = grTaskInst.assigned_to;
			// RJ - STRY0065465 there is no longer an 'Assigne_to_type, just assign group, if assigned, it will just assign null if it wasn't selected in template. The group is now the restricted group in both template and task
			current.assigned_to_group = grTaskInst.assignment_group;

			current.instructions = grTaskInst.instructions;
			current.u_objective = grTaskInst.u_objective;
			current.category = grTaskInst.category;
			current.warning_hours = grTaskInst.warning_hours;
			current.classification = grTaskInst.classification;
			current.primary_assignee = grTaskInst.primary_assignee;
			current.primary_office = grTaskInst.primary_office;
			current.route_order = grTaskInst.order;
			current.short_description = grTaskInst.short_description;
			current.sub_category = grTaskInst.sub_category;
			// RAJ - Duration was not copied down and should have been
			current.duration = grTaskInst.calendar_duration;
			// STRY0076904
			current.u_wait_for_subtasks_to_finish = grTaskInst.u_wait_for_subtasks_to_finish;

			current.tasker_type = grTaskInst.tasker_type;
			current.tasking_authority = grTaskInst.tasking_authority;
			current.demo_data = grTaskInst.demo_data;
			// STRY0075898
			current.u_external_ou = grTaskInst.u_external_ou;
			current.poc_name = grTaskInst.poc_name;
			current.outbound = grTaskInst.outbound;
			current.u_internal_contact = grTaskInst.u_internal_contact;

			// STRY0085130
			current.tasker_type = grTaskInst.tasker_type;
			current.u_signature_instructions = grTaskInst.u_signature_instructions;
			current.u_reviewer = grTaskInst.u_reviewer;
			current.provide_response = grTaskInst.provide_response;
			current.u_on_behalf_of = grTaskInst.on_behalf_of;

			current.u_internal_contact_performing_task = grTaskInst.u_internal_contact_performing_task;
			// STRY0065506 - added  fields added to the Template Task for parity
			current.u_priority = grTaskInst.priority;
			current.u_urgency = grTaskInst.urgency;
			current.u_reviewer = grTaskInst.u_reviewer;
			current.u_risk_flag = grTaskInst.risk_flag;
			current.u_risk_impact_description = grTaskInst.risk_impact_description;
			current.u_risk_impact_factor = grTaskInst.risk_impact_factor;
			current.u_risk_mitigation_strategy = grTaskInst.risk_mitigation_strategy;
			current.u_risk_probability = grTaskInst.risk_probability;
			current.u_risk_probability_description = grTaskInst.risk_probability_description;
			current.u_risk_reason = grTaskInst.risk_reason;
			current.u_signature_instructions = grTaskInst.u_signature_instructions;

			// STRY0084599 - Need a way for deliver and customers to better synchronize field updates and changes
			current = new CustomTaskerFieldHelper().mapFieldDataOnAction('templateTaskSaveAsTemplateCopyFromTask', grTaskInst, current);
		}
	}


})(current, previous);
